[ExtensionOf(tableStr(ITMTable))]
internal final class ETGITMTable_Table_Extension
{
}

Method.Source:
display SalesStatus salesStatusETG()
{
    if (this.ETGLandedCostType ==  ETGLandedCostType::Outbound)
    {
        ITMLine itmLineOUT;
        select firstonly TransType, TransRefId from itmLineOUT where itmLineOUT.ShipId == this.ShipId;

        if(itmLineOUT.TransType == InventTransType::Sales && itmLineOUT.TransRefId)
        {
            return SalesTable::find(itmLineOUT.TransRefId).SalesStatus;
        }
    }

    return SalesStatus::None;
}

public void insert()
{
    if(this.ETGLandedCostType == ETGLandedCostType::Outbound)
    {
        this.ETGOTMITMId = this.ShipId;
    }
    next insert();
}
